#!/usr/bin/perl

use strict;
use warnings;

my %word_count = ();

if (@ARGV < 1) {
    die "Usage: $0 filename\n";
}

open my $fh, '<', $ARGV[0] or die "Cannot open file '$ARGV[0]' for reading: $!\n";

while (my $line = <$fh>) {
    chomp $line;
    foreach my $word (split /\s/, $line) {
        $word =~ s/^\W+|\W+$//g; # Remove non-word characters
        $word = lc($word);         # Convert to lowercase

        if ($word ne '') {
            $word_count{$word}++;
        }
    }
}

close $fh;

my @top_words = sort { $b <=> $a } keys %word_count;
for my $i (0..2) {
    print "$top_words[$i]: $word_count{$_}\n" for 0..$#top_words;
}

use strict;
use warnings;

open my $fh, '<', $ARGV[0] or die "Cannot open file: $!";
while (my $line = <$fh>) {
    chomp $line;
    if ($line =~ /^\s*(\d+),(\d+),(.*)$/) {
        my ($age, $name, $city) = ($1, $2, $3);
        next unless $age > 30;
        print "$name,$age,$city\n";
    }
}
close $fh;

use strict;
use warnings;

my $filename = $ARGV[0];
open my $fh, '<', $filename or die "Cannot open file '$filename': $!";
while (my $line = <$fh>) {
    while ($line =~ /[\w.-]+@[\w.-]+\.[\w]{2,}/g) {
        print "$_\n";
    }
}
close $fh;
